using Microsoft.EntityFrameworkCore.Migrations;

#nullable disable

namespace KafeYana.Infrastructure.Migrations
{
    /// <summary>
    /// Arregla la tabla "Detalle_Pago" agregando la numeración automática (IDENTITY) a la columna "Id".
    ///
    /// Causa: la tabla fue creada con un script SQL manual en Azure que omitió
    ///        "GENERATED BY DEFAULT AS IDENTITY" (o "SERIAL"). El modelo EF Core
    ///        sí la declara como identity, pero EF al hacer INSERT enviaba "Id = 0"
    ///        chocando con "PK_Detalle_Pago" en cuanto la tabla tenía ≥1 fila.
    ///
